import os 
# store for test data to be used in testing

# Personalise output data to user --------------------------------------------------------------------------------------------------------------

def user_customised_outputs(output_to_personalise, output_type):
    ''' 
    This function takes an input of data which needs it's path to be personalised for testing 
    and what the output type is currently can be string or list and support tool is 
    used to create the correct path to the decision_support_tool script 
    The inputted data should have the placeholder "user_document_root" 
    which will then be replaced by this function
    Input = data to be personalised and data type
    Output = personalised data to be used in testing 
    '''
    if output_type == 'strings':
        user_document_root = "/".join(os.path.dirname(os.path.realpath(__file__)).split("/"))
        personalised_output = output_to_personalise.replace("user_document_root", user_document_root)
    elif output_type == 'lists':
        user_document_root = "/".join(os.path.dirname(os.path.realpath(__file__)).split("/"))
        personalised_output = [user_string.replace("user_document_root", user_document_root) for user_string in output_to_personalise]
    elif output_type == 'support_tool':
        user_document_root = "/".join(os.path.dirname(os.path.realpath(__file__)).split("/")[:-2])
        user_path_support_tool = ("{user_document_root}/automate_demultiplex/decision_support_tool_inputs.py").format(user_document_root=user_document_root)
        personalised_output = [user_string.replace("placeholder_path_to_decision_support_tool", user_path_support_tool) for user_string in output_to_personalise]
    else: print('type not supported')
    return personalised_output
                
     


